def checkInclusion(s1: str, s2: str) -> bool:
    if len(s1) > len(s2):
        return False
    c1 = [0] * 26
    c2 = [0] * 26
    for i in range(len(s1)):
        c1[ord(s1[i]) - 97] += 1
        c2[ord(s2[i]) - 97] += 1
    matches = 0
    for i in range(26):
        if c1[i] == c2[i]:
            matches += 1
    for i in range(len(s2) - len(s1)):
        if matches == 26:
            return True
        r = ord(s2[i + len(s1)]) - 97
        l = ord(s2[i]) - 97
        c2[r] += 1
        if c2[r] == c1[r]:
            matches += 1
        elif c2[r] == c1[r] + 1:
            matches -= 1
        c2[l] -= 1
        if c2[l] == c1[l]:
            matches += 1
        elif c2[l] == c1[l] - 1:
            matches -= 1
    return matches == 26

