        self.counts = {}

    def add(self, point: list[int]) -> None:
        x, y = point[0], point[1]
        if x not in self.counts:
            self.counts[x] = {}
        self.counts[x][y] = self.counts[x].get(y, 0) + 1

    def count(self, point: list[int]) -> int:
        qx, qy = point[0], point[1]
        ans = 0
        if qx not in self.counts:
            return 0
        for py in self.counts[qx]:
            if py == qy:
                continue
            side = abs(py - qy)
            for px in [qx + side, qx - side]:
                if px in self.counts:
                    ans += self.counts[qx][py] * self.counts[px].get(qy, 0) * self.counts[px].get(py, 0)
        return ans

