class ElevatorSystem:
    def __init__(self, num_floors: int, num_elevators: int):
        self.num_floors = num_floors
        self.elevators = [
            {"floor": 1, "direction": 1, "requests": set()}
            for _ in range(num_elevators)
        ]

    def request(self, floor: int) -> None:
        def score(e):
            distance = abs(e["floor"] - floor)
            heading_toward = (
                (e["direction"] == 1 and floor >= e["floor"]) or
                (e["direction"] == -1 and floor <= e["floor"])
            )
            is_idle = not e["requests"]

            if is_idle:
                return distance + 1
            if heading_toward:
                return distance
            return distance + self.num_floors

        best = min(self.elevators, key=score)
        best["requests"].add(floor)

    def step(self, elevator_id: int) -> int:
        e = self.elevators[elevator_id]
        e["floor"] += e["direction"]
        e["requests"].discard(e["floor"])

        above = any(f > e["floor"] for f in e["requests"])
        below = any(f < e["floor"] for f in e["requests"])

        if e["direction"] == 1 and not above:
            e["direction"] = -1
        elif e["direction"] == -1 and not below:
            e["direction"] = 1

        return e["floor"]

    def get_current_floor(self, elevator_id: int) -> int:
        return self.elevators[elevator_id]["floor"]

    def get_direction(self, elevator_id: int) -> str:
        e = self.elevators[elevator_id]
        if not e["requests"]:
            return "idle"
        return "up" if e["direction"] == 1 else "down"

    def has_pending_requests(self, elevator_id: int) -> bool:
        return len(self.elevators[elevator_id]["requests"]) > 0

