            if val < node.val:
                node.left = _delete(node.left, val)
            elif val > node.val:
                node.right = _delete(node.right, val)
            else:
                if not node.left:
                    return node.right
                if not node.right:
                    return node.left
                temp = _min_node(node.right)
                node.val = temp.val
                node.right = _delete(node.right, temp.val)
            return node
