        self.root = {}

    def addWord(self, word: str) -> None:
        curr = self.root
        for c in word:
            if c not in curr:
                curr[c] = {}
            curr = curr[c]
        curr["$"] = True

    def search(self, word: str) -> bool:
        def dfs(node, i):
            if i == len(word):
                return "$" in node
            c = word[i]
            if c == ".":
                for child in node:
                    if child != "$" and dfs(node[child], i + 1):
                        return True
                return False
            if c in node:
                return dfs(node[c], i + 1)
            return False
        return dfs(self.root, 0)

