def leastInterval(tasks: list[str], n: int) -> int:
    counts = Counter(tasks)
    max_val = max(counts.values())
    max_val_count = sum(1 for cnt in counts.values() if cnt == max_val)
    return max(len(tasks), (max_val - 1) * (n + 1) + max_val_count)

