class MinHeap:
    def __init__(self):
        self.heap = []

    def push(self, val: int) -> None:
        self.heap.append(val)
        self._up(len(self.heap) - 1)

    def pop(self) -> int:
        if not self.heap:
            return -1
        if len(self.heap) == 1:
            return self.heap.pop()
        res = self.heap[0]
        self.heap[0] = self.heap.pop()
        self._down(0)
        return res

    def peek(self) -> int:
        return self.heap[0] if self.heap else -1

    def _up(self, idx):
        while idx > 0:
            p = (idx - 1) // 2
            if self.heap[idx] < self.heap[p]:
                self.heap[idx], self.heap[p] = self.heap[p], self.heap[idx]
                idx = p
            else:
                break

    def _down(self, idx):
        n = len(self.heap)
        while 2 * idx + 1 < n:
            left = 2 * idx + 1
            right = 2 * idx + 2
            smallest = left
            if right < n and self.heap[right] < self.heap[left]:
                smallest = right
            if self.heap[smallest] < self.heap[idx]:
                self.heap[idx], self.heap[smallest] = self.heap[smallest], self.heap[idx]
                idx = smallest
            else:
                break

