def longestDiverseString(a: int, b: int, c: int) -> str:
    h = []
    for cnt, char in [(a, "a"), (b, "b"), (c, "c")]:
        if cnt > 0:
            heapq.heappush(h, (-cnt, char))
    res = []
    while h:
        cnt1, char1 = heapq.heappop(h)
        if len(res) >= 2 and res[-1] == char1 and res[-2] == char1:
            if not h:
                break
            cnt2, char2 = heapq.heappop(h)
            res.append(char2)
            if cnt2 + 1 < 0:
                heapq.heappush(h, (cnt2 + 1, char2))
            heapq.heappush(h, (cnt1, char1))
        else:
            res.append(char1)
            if cnt1 + 1 < 0:
                heapq.heappush(h, (cnt1 + 1, char1))
    return "".join(res)

