def carPooling(trips: list[list[int]], capacity: int) -> bool:
    events = []
    for num, start, end in trips:
        events.append((start, num))
        events.append((end, -num))
    events.sort(key=lambda x: (x[0], x[1]))
    curr = 0
    for _, num in events:
        curr += num
        if curr > capacity:
            return False
    return True

