def mergeKLists(lists: list[Optional[ListNode]]) -> Optional[ListNode]:
    h = []
    for idx, head in enumerate(lists):
        if head:
            heapq.heappush(h, (head.val, idx, head))
    dummy = ListNode()
    curr = dummy
    while h:
        val, idx, node = heapq.heappop(h)
        curr.next = node
        curr = curr.next
        if node.next:
            heapq.heappush(h, (node.next.val, idx, node.next))
    return dummy.next

