def findMaximizedCapital(k: int, w: int, profits: list[int], capital: list[int]) -> int:
    projects = sorted(zip(capital, profits), key=lambda x: x[0])
    h = []
    idx = 0
    n = len(projects)
    for _ in range(k):
        while idx < n and projects[idx][0] <= w:
            heapq.heappush(h, -projects[idx][1])
            idx += 1
        if not h:
            break
        w += -heapq.heappop(h)
    return w

