def hasPathSum(root: Optional[TreeNode], targetSum: int) -> bool:
    if not root:
        return False
    if not root.left and not root.right:
        return root.val == targetSum
    return (
        hasPathSum(root.left, targetSum - root.val)
        or hasPathSum(root.right, targetSum - root.val)
    )

