def permuteUnique(nums: list[int]) -> list[list[int]]:
    res = []
    nums.sort()
    def dfs(path, used):
        if len(path) == len(nums):
            res.append(path)
            return
        for i in range(len(nums)):
            if used[i]:
                continue
            if i > 0 and nums[i] == nums[i - 1] and not used[i - 1]:
                continue
            used[i] = True
            dfs(path + [nums[i]], used)
            used[i] = False
    dfs([], [False] * len(nums))
    return sorted(res)

