def canPartitionKSubsets(nums: list[int], k: int) -> bool:
    total = sum(nums)
    if total % k != 0:
        return False
    target = total // k
    nums.sort(reverse=True)
    used = [False] * len(nums)
    def dfs(k_left, idx, curr_sum):
        if k_left == 0:
            return True
        if curr_sum == target:
            return dfs(k_left - 1, 0, 0)
        for i in range(idx, len(nums)):
            if used[i] or curr_sum + nums[i] > target:
                continue
            used[i] = True
            if dfs(k_left, i + 1, curr_sum + nums[i]):
                return True
            used[i] = False
            if curr_sum == 0:
                break
        return False
    return dfs(k, 0, 0)

