def wordBreak(s: str, wordDict: list[str]) -> list[str]:
    words = set(wordDict)
    memo = {}
    def dfs(idx):
        if idx in memo:
            return memo[idx]
        if idx == len(s):
            return [""]
        res = []
        for end in range(idx + 1, len(s) + 1):
            word = s[idx:end]
            if word in words:
                sub_res = dfs(end)
                for r in sub_res:
                    res.append(word + (" " + r if r else ""))
        memo[idx] = res
        return res
    return sorted(dfs(0))

