def floodFill(image: list[list[int]], sr: int, sc: int, color: int) -> list[list[int]]:
    m, n = len(image), len(image[0])
    orig = image[sr][sc]
    if orig == color:
        return image
    def dfs(r, c):
        if image[r][c] == orig:
            image[r][c] = color
            for dr, dc in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n:
                    dfs(nr, nc)
    dfs(sr, sc)
    return image

