class Graph:
    def __init__(self, directed: bool = False):
        self.directed = directed
        self.adj = {}

    def add_edge(self, src: int, dst: int) -> None:
        if src not in self.adj:
            self.adj[src] = set()
        if dst not in self.adj:
            self.adj[dst] = set()
        self.adj[src].add(dst)
        if not self.directed:
            self.adj[dst].add(src)

    def remove_edge(self, src: int, dst: int) -> None:
        if src in self.adj and dst in self.adj[src]:
            self.adj[src].remove(dst)
        if not self.directed:
            if dst in self.adj and src in self.adj[dst]:
                self.adj[dst].remove(src)

    def neighbors(self, val: int) -> list[int]:
        if val not in self.adj:
            return []
        return sorted(list(self.adj[val]))

    def bfs(self, start: int) -> list[int]:
        visited = {start}
        queue = [start]
        res = []
        head = 0
        while head < len(queue):
            curr = queue[head]
            head += 1
            res.append(curr)
            for neighbor in sorted(list(self.adj.get(curr, []))):
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
        return res

    def dfs(self, start: int) -> list[int]:
        visited = set()
        res = []
        def _dfs(node):
            visited.add(node)
            res.append(node)
            for nxt in sorted(list(self.adj.get(node, []))):
                if nxt not in visited:
                    _dfs(nxt)
        _dfs(start)
        return res

    def has_cycle(self) -> bool:
        if self.directed:
            visited = set()
            rec_stack = set()
            def dfs_directed(node):
                visited.add(node)
                rec_stack.add(node)
                for neighbor in self.adj.get(node, []):
                    if neighbor not in visited:
                        if dfs_directed(neighbor):
                            return True
                    elif neighbor in rec_stack:
                        return True
                rec_stack.remove(node)
                return False
            for node in self.adj:
                if node not in visited:
                    if dfs_directed(node):
                        return True
            return False
        else:
            visited = set()
            def dfs_undirected(node, parent):
                visited.add(node)
                for neighbor in self.adj.get(node, []):
                    if neighbor not in visited:
                        if dfs_undirected(neighbor, node):
                            return True
                    elif neighbor != parent:
