def findCriticalAndPseudoCriticalEdges(n: int, edges: list[list[int]]) -> list[list[int]]:
    class UnionFind:
        def __init__(self, size):
            self.parent = list(range(size))
            self.count = size
        def find(self, i):
            if self.parent[i] == i:
                return i
            self.parent[i] = self.find(self.parent[i])
            return self.parent[i]
        def union(self, i, j):
            root1 = self.find(i)
            root2 = self.find(j)
            if root1 != root2:
                self.parent[root1] = root2
                self.count -= 1
                return True
            return False
    edges_with_idx = []
    for i, edge in enumerate(edges):
        edges_with_idx.append((edge[0], edge[1], edge[2], i))
    edges_with_idx.sort(key=lambda x: x[2])
    def get_mst_weight(block_idx=-1, force_idx=-1):
        uf = UnionFind(n)
        weight = 0
        if force_idx != -1:
            for u, v, w, idx in edges_with_idx:
                if idx == force_idx:
                    uf.union(u, v)
                    weight += w
                    break
        for u, v, w, idx in edges_with_idx:
            if idx == block_idx:
                continue
            if uf.union(u, v):
                weight += w
        return weight if uf.count == 1 else float("inf")
    std_weight = get_mst_weight()
    critical = []
    pseudo = []
    for i in range(len(edges)):
        if get_mst_weight(block_idx=i) > std_weight:
            critical.append(i)
        elif get_mst_weight(force_idx=i) == std_weight:
            pseudo.append(i)
    return [critical, pseudo]

