def criticalConnections(n: int, connections: list[list[int]]) -> list[list[int]]:
    adj = {i: [] for i in range(n)}
    for u, v in connections:
        adj[u].append(v)
        adj[v].append(u)
    dfn = [-1] * n
    low = [-1] * n
    bridges = []
    time = 0
    parent_map = [-1] * n
    stack = [0]
    edge_idx = [0] * n
    dfn[0] = low[0] = 0
    time = 1
    while stack:
        u = stack[-1]
        p = parent_map[u]
        if edge_idx[u] < len(adj[u]):
            v = adj[u][edge_idx[u]]
            edge_idx[u] += 1
            if v == p:
                continue
            if dfn[v] == -1:
                dfn[v] = low[v] = time
                time += 1
                parent_map[v] = u
                stack.append(v)
            else:
                low[u] = min(low[u], dfn[v])
        else:
            stack.pop()
            if p != -1:
                low[p] = min(low[p], low[u])
                if low[u] > dfn[p]:
                    bridges.append(sorted([p, u]))
    return sorted(bridges)

