def buildMatrix(k: int, rowConditions: list[list[int]], colConditions: list[list[int]]) -> list[list[int]]:
    from collections import deque
    def topo_sort(conds):
        adj = {i: [] for i in range(1, k + 1)}
        in_degree = [0] * (k + 1)
        for u, v in conds:
            adj[u].append(v)
            in_degree[v] += 1
        q = deque([i for i in range(1, k + 1) if in_degree[i] == 0])
        order = []
        while q:
            curr = q.popleft()
            order.append(curr)
            for neighbor in adj[curr]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    q.append(neighbor)
        return order if len(order) == k else []
    row_order = topo_sort(rowConditions)
    col_order = topo_sort(colConditions)
    if not row_order or not col_order:
        return []
    row_pos = {val: i for i, val in enumerate(row_order)}
    col_pos = {val: i for i, val in enumerate(col_order)}
    matrix = [[0] * k for _ in range(k)]
    for val in range(1, k + 1):
        matrix[row_pos[val]][col_pos[val]] = val
    return matrix

