def canTraverseAllPairs(nums: list[int]) -> bool:
    if len(nums) == 1:
        return True
    if 1 in nums:
        return False
    n = len(nums)
    parent = list(range(n))
    def find(i):
        if parent[i] == i:
            return i
        parent[i] = find(parent[i])
        return parent[i]
    def union(i, j):
        root1 = find(i)
        root2 = find(j)
        if root1 != root2:
            parent[root1] = root2
            return True
        return False
    prime_to_idx = {}
    for i, val in enumerate(nums):
        temp = val
        d = 2
        while d * d <= temp:
            if temp % d == 0:
                if d in prime_to_idx:
                    union(i, prime_to_idx[d])
                else:
                    prime_to_idx[d] = i
                while temp % d == 0:
                    temp //= d
            d += 1
        if temp > 1:
            if temp in prime_to_idx:
                union(i, prime_to_idx[temp])
            else:
                prime_to_idx[temp] = i
    roots = set(find(i) for i in range(n))
    return len(roots) == 1

