def lengthOfLIS(nums: list[int]) -> int:
    import bisect
    sub = []
    for val in nums:
        idx = bisect.bisect_left(sub, val)
        if idx == len(sub):
            sub.append(val)
        else:
            sub[idx] = val
    return len(sub)

