def numSquares(n: int) -> int:
    dp = [float("inf")] * (n + 1)
    dp[0] = 0
    for i in range(1, n + 1):
        j = 1
        while j * j <= i:
            dp[i] = min(dp[i], dp[i - j*j] + 1)
            j += 1
    return dp[n]

277:
def integerBreak(n: int) -> int:
    if n <= 3:
        return n - 1
    quotient, remainder = n // 3, n % 3
    if remainder == 0:
        return 3 ** quotient
    elif remainder == 1:
        return 3 ** (quotient - 1) * 4
    else:
        return 3 ** quotient * 2

