def maxProfit(prices: list[int]) -> int:
    if not prices:
        return 0
    cool, sell, hold = 0, 0, float("-inf")
    for price in prices:
        prev_cool = cool
        cool = max(cool, sell)
        sell = hold + price
        hold = max(hold, prev_cool - price)
    return max(cool, sell)

