def findTargetSumWays(nums: list[int], target: int) -> int:
    total = sum(nums)
    if abs(target) > total or (total + target) % 2 != 0:
        return 0
    target_sum = (total + target) // 2
    dp = [0] * (target_sum + 1)
    dp[0] = 1
    for num in nums:
        for i in range(target_sum, num - 1, -1):
            dp[i] += dp[i - num]
    return dp[target_sum]

