def isInterleave(s1: str, s2: str, s3: str) -> bool:
    if len(s1) + len(s2) != len(s3):
        return False
    dp = [False] * (len(s2) + 1)
    for i in range(len(s1) + 1):
        for j in range(len(s2) + 1):
            if i == 0 and j == 0:
                dp[j] = True
            elif i == 0:
                dp[j] = dp[j - 1] and s2[j - 1] == s3[j - 1]
            elif j == 0:
                dp[j] = dp[j] and s1[i - 1] == s3[i - 1]
            else:
                dp[j] = (dp[j] and s1[i - 1] == s3[i + j - 1]) or (dp[j - 1] and s2[j - 1] == s3[i + j - 1])
    return dp[-1]

291:
def stoneGameII(piles: list[int]) -> int:
    n = len(piles)
    suffix_sums = [0] * (n + 1)
    for i in range(n - 1, -1, -1):
        suffix_sums[i] = suffix_sums[i + 1] + piles[i]
    memo = {}
    def dp(i, m):
        if i >= n:
            return 0
        if (i, m) in memo:
            return memo[(i, m)]
        if i + 2 * m >= n:
            return suffix_sums[i]
        res = suffix_sums[i] - min(dp(i + x, max(m, x)) for x in range(1, 2 * m + 1))
        memo[(i, m)] = res
        return res
    return dp(0, 1)

